}

console.log(descrever("Aria", 5));

// Função tradicional:
function dobrar(n: number): number {
  return n * 2;
}

// Arrow function equivalente:
const dobrarArrow = (n: number): number => {
  return n * 2;
};

// Arrow function curta (uma expressão):
const dobrarCurta = (n: number): number => n * 2;

console.log(dobrar(5));
console.log(dobrarArrow(5));
console.log(dobrarCurta(5));

lessons.instructions:
Crie 3 funções:

1. `dobrar(n: number): number` → retorna `n * 2`
2. `somar(a: number, b: number): number` → retorna `a + b`
3. `media(a: number, b: number, c: number): number` → retorna a média dos 3 números

Depois teste com:
```
console.log(dobrar(7));
console.log(somar(10, 20));
console.log(media(8, 9, 10));
```

