lessons.solution:
function dobrar(n: number): number {
  return n * 2;
}

function somar(a: number, b: number): number {
  return a + b;
}

function media(a: number, b: number, c: number): number {
  return (a + b + c) / 3;
}

console.log(dobrar(7));
console.log(somar(10, 20));
console.log(media(8, 9, 10));

