lessons.solution:
function calcular(a: number, b: number, operacao: string): number {
  if (operacao === "+") {
    return a + b;
  } else if (operacao === "-") {
    return a - b;
  } else if (operacao === "*") {
    return a * b;
  } else if (operacao === "/") {
    return a / b;
  } else {
    return 0;
  }
}

console.log(calcular(10, 3, "+"));
console.log(calcular(10, 3, "-"));
console.log(calcular(10, 3, "*"));
console.log(calcular(10, 3, "/"));
